{
var op = GetChoice(parameters, "operation", "add");
    var strength = GetFloat(parameters, "strength", 1f);
    var constant = GetFloat(parameters, "constant", 0f);
    var useConstant = GetBool(parameters, "useConstant", true);

    var size = context.TileSize;
    var result = new PixelBuffer(size, size);

    var inputA = inputs.Length > 0 ? inputs[0] : null;
    var inputB = useConstant ? null : (inputs.Length > 1 ? inputs[1] : null);

    result.ParallelForEachPixel((x, y) =>
    {
        float ra, ga, ba, aa;
        float rb, gb, bb, ab;

        if (inputA != null)
        {
            (ra, ga, ba, aa) = inputA.GetPixel(x, y);
        }
        else
        {
            ra = ga = ba = aa = 0f;
        }

        if (inputB != null)
        {
            (rb, gb, bb, ab) = inputB.GetPixel(x, y);
        }
        else if (useConstant)
        {
            rb = gb = bb = constant;
            ab = 1f;
        }
        else
        {
            rb = gb = bb = 0f;
            ab = 1f;
        }

        float rr, gr, br, ar;
        ApplyOp(ra, ga, ba, aa, rb, gb, bb, ab, op, strength, out rr, out gr, out br, out ar);

        result.SetPixel(x, y, rr, gr, br, ar);
    });

    return result;

private static void ApplyOp(float ra, float ga, float ba, float aa,
    float rb, float gb, float bb, float ab,
    string op, float strength,
    out float rr, out float gr, out float br, out float ar)
{
    switch (op)
    {
        case "add":
            rr = Math.Clamp(ra + rb * strength, 0, 1);
            gr = Math.Clamp(ga + gb * strength, 0, 1);
            br = Math.Clamp(ba + bb * strength, 0, 1);
            break;
        case "subtract":
            rr = Math.Clamp(ra - rb * strength, 0, 1);
            gr = Math.Clamp(ga - gb * strength, 0, 1);
            br = Math.Clamp(ba - bb * strength, 0, 1);
            break;
        case "multiply":
            rr = Math.Clamp(ra * Math.Max(0, rb * strength + (1 - strength)), 0, 1);
            gr = Math.Clamp(ga * Math.Max(0, gb * strength + (1 - strength)), 0, 1);
            br = Math.Clamp(ba * Math.Max(0, bb * strength + (1 - strength)), 0, 1);
            break;
        case "divide":
            rr = rb > 0.001f ? Math.Clamp(ra / (rb * strength + 0.001f), 0, 1) : ra;
            gr = gb > 0.001f ? Math.Clamp(ga / (gb * strength + 0.001f), 0, 1) : ga;
            br = bb > 0.001f ? Math.Clamp(ba / (bb * strength + 0.001f), 0, 1) : ba;
            break;
        case "max":
            rr = Math.Max(ra, rb * strength + ra * (1 - strength));
            gr = Math.Max(ga, gb * strength + ga * (1 - strength));
            br = Math.Max(ba, bb * strength + ba * (1 - strength));
            break;
        case "min":
            rr = Math.Min(ra, rb * strength + ra * (1 - strength));
            gr = Math.Min(ga, gb * strength + ga * (1 - strength));
            br = Math.Min(ba, bb * strength + ba * (1 - strength));
            break;
        case "absoluteDifference":
            rr = Math.Clamp(Math.Abs(ra - rb) * strength + ra * (1 - strength), 0, 1);
            gr = Math.Clamp(Math.Abs(ga - gb) * strength + ga * (1 - strength), 0, 1);
            br = Math.Clamp(Math.Abs(ba - bb) * strength + ba * (1 - strength), 0, 1);
            break;
        case "screenBlend":
            rr = Math.Clamp(1 - (1 - ra) * (1 - rb * strength), 0, 1);
            gr = Math.Clamp(1 - (1 - ga) * (1 - gb * strength), 0, 1);
            br = Math.Clamp(1 - (1 - ba) * (1 - bb * strength), 0, 1);
            break;
        default:
            rr = ra; gr = ga; br = ba;
            break;
    }
    ar = Math.Max(aa, ab);
    }
}
